    private string? MobileNumber { get; set; }
    private string? Message { get; set; }
    private bool IsSuccess { get; set; }
    private bool IsLoading { get; set; }

    private async Task HandleGetOTP()
    {
        if (string.IsNullOrWhiteSpace(MobileNumber))
        {
            Message = "Please enter a mobile number";
            IsSuccess = false;
            return;
        }

        IsLoading = true;
        Message = null;

        var result = await AuthService.GetOTPAsync(MobileNumber);

        if (result.IsSuccess)
        {
            // Store the entered mobile number in UserSession for later use (logout, etc.)
            await UserSession.SetMobileNoAsync(MobileNumber);
            // Navigate to OTP verification page, passing the mobile number
            Navigation.NavigateTo($"/otp-verification?mobile={Uri.EscapeDataString(MobileNumber)}");
        }
        else
        {
            Message = result.Message;
            IsSuccess = false;
        }

        IsLoading = false;
    }

